<?php
require __DIR__ . '/bootstrap.php';
$rows=[];if(defined('HS_INSTALLED')&&HS_INSTALLED){$r=mysqli_query(hs_db(),"SELECT title,slug,excerpt,created_at FROM hs_posts WHERE status='published' AND is_trending=1 ORDER BY created_at DESC LIMIT 30");if($r)$rows=mysqli_fetch_all($r,MYSQLI_ASSOC);}?>
<!doctype html><html><head><meta charset='utf-8'><meta name='viewport' content='width=device-width, initial-scale=1'><title>Trending</title><link rel='stylesheet' href='<?= hs_base_url('assets/css/style.css') ?>'><?= hs_pwa_head_tags() ?><script defer src='<?= hs_base_url('assets/js/pwa.js') ?>'></script></head><body><main class='page-bg'><div class='container'><div class='section-head'><h1>Trending</h1></div><div class='card-grid'><?php foreach($rows as $p):?><article class='news-card'><h3><a href='<?= hs_base_url('post.php?slug='.urlencode($p['slug'])) ?>'><?= htmlspecialchars($p['title']) ?></a></h3><p><?= htmlspecialchars($p['excerpt']??'') ?></p></article><?php endforeach; if(empty($rows)):?><div class='panel'>No trending stories right now.</div><?php endif;?></div></div></main></body></html>
